<template>
  <!-- ==============================================
    ** Inner Banner **
    =================================================== -->
  <div class="inner-banner blog">
    <div class="container">
      <div class="row">
        <div class="col-sm-12">
          <div class="content">
            <h1>PUBLICACIONES ACTUALES DE LA CARRERA</h1>
          </div>

          <h4>
            <router-link to="/">INICIO</router-link>
          </h4>
          <h5>PUBLICACIONES</h5>
        </div>
      </div>
    </div>
  </div>

  <!-- ==============================================
    ** Blog **
    =================================================== -->
  <div class="container blog-wrapper padding-lg">
    <div v-if="Publicaciones.length == 0">
      <h2>SIN PUBLICACIONES</h2>
    </div>

    <div
      v-else
      class="row"
      v-for="(pub, id_pub) of Publicaciones"
      :key="id_pub"
    >
      <!-- Start Left Column -->
      <div class="col-sm-8 blog-left">
        <div class="blog-listing">
          <!-- <li> -->
            <!-- <router-link
                    :to="'/detallePublicacion/' + pub.publicaciones_id"
                    @click="$store.commit('clickLink')"
                  > -->
            <img
              style="width: 750px; height: 270px"
              :src="url_api + '/Publicaciones/' + pub.publicaciones_imagen"
              class="img-responsive"
              alt=""
            />
            <!-- </router-link> -->

            <div class="left-aligned">
              <ul class="post-detail">
                <li>
                  <span class="icon-date-icon ico"></span
                  ><span class="bold">{{ dmy(pub.publicaciones_fecha) }}</span>
                </li>
                <li>
                  Publicado por:
                  <span class="bold">{{ pub.publicaciones_autor }}</span>
                </li>
                <li><span class="label">PUBLICACIONES</span></li>
              </ul>

              <h2>
                <router-link
                  :to="'/detallePublicacion/' + pub.publicaciones_id"
                  @click="$store.commit('clickLink')"
                >
                  {{ pub.publicaciones_titulo }}
                </router-link>
              </h2>

              <router-link
                :to="'/detallePublicacion/' + pub.publicaciones_id"
                @click="$store.commit('clickLink')"
                class="read-more"
                ><span class="icon-play-icon"></span>
                Leer más
              </router-link>
            </div>
          <!-- </li> -->
        </div>
      </div>
      <!-- End Left Column -->

      <!-- Start Right Column -->
      <div class="col-sm-4">
        <SidebarCustom> </SidebarCustom>
      </div>
      <!-- End Right Column -->
    </div>
    
    <div class="text-center">
      <ul class="pagination blue">
        <li class="pagination-arrow disable">
          <a
            href="#"
            aria-label="Previous"
            @click.prevent="pag != 1 ? (pag -= 1) : ''"
          >
            <span aria-hidden="true">
              <i class="fa fa-angle-left" aria-hidden="true"> </i>
            </span>
          </a>
        </li>

        <!-- <li v-for="(i, index) of pager" :key="index">
          <a href="#" :class="[i == pag ? 'active' : '']" @click.prevent="pag = i">
            {{ i }}
          </a>
        </li> -->
        <li v-for="(i, index) of totalPages" :key="index">
          <a
            href="#"
            :class="[i === pag ? 'active' : '']"
            @click.prevent="
              pag = i;
              scrollToTop();
            "
          >
            {{ i }}
          </a>
        </li>

        <li>
          <a
            href="#"
            aria-label="Next"
            @click.prevent="pag != pager ? (pag += 1) : ''"
          >
            <span aria-hidden="true">
              <i class="fa fa-angle-right" aria-hidden="true"> </i>
            </span>
          </a>
        </li>
      </ul>
    </div>
  </div>
</template>

<style scoped>
.bg-overlay-img {
  background-image: url("@/assets/Fondo2.jpg");
}
</style>

<script>
import SidebarCustom from "@/components/SidebarCustom.vue";
import { mapState } from "vuex";
// import HeaderCustom from "@/components/HeaderCustom.vue";
// import SidebarCustom from "@/components/SidebarCustom.vue";
export default {
  name: "PublicacionesView",
  data() {
    return {
      perPage: 4, //===

      Publicaciones: [],
      search: "",
      searchGet: false,
      searchValues: [],

      NUM_RESULTS: 4,
      pag: 1,
      pager: 0,
    };
  },
  components: {
    SidebarCustom,
  },
  computed: {
    totalPages() {
      //---
      return Math.ceil(this.Publicaciones.length / this.perPage);
    },

    ...mapState(["url_api", "getter"]),
  },
  methods: {
    scrollToTop() {
      //---
      window.scrollTo({
        top: 0,
        behavior: "smooth", // Para un desplazamiento suave
      });
    },
    async getPublicaciones() {
      try {
        let res = await this.axios.get(
          "/api/PublicacionesAll/" + process.env.VUE_APP_ID_INSTITUCION
        );
        this.Publicaciones = res.data;
        this.pager = this.Publicaciones.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
    clickBack() {
      this.$store.commit("clickLink");
      this.$router.go(-1);
    },
    dmy(fecha) {
      const meses = [
        "enero",
        "febrero",
        "marzo",
        "abril",
        "mayo",
        "junio",
        "julio",
        "agosto",
        "septiembre",
        "octubre",
        "noviembre",
        "diciembre",
      ];
      let fechaCadena = fecha.substr(0, 10);
      let fechaArray = fechaCadena.split("-");
      return (
        fechaArray[2] +
        " de " +
        meses[fechaArray[1] - 1] +
        " de " +
        fechaArray[0]
      );
    },
    buscar() {
      if (this.search != "") {
        this.searchGet = true;

        this.searchValues = [];
        this.Publicaciones.forEach((pub) => {
          if (
            pub.publicaciones_titulo
              .toUpperCase()
              .includes(this.search.toUpperCase())
          ) {
            this.searchValues.push(pub);
          }
        });
      } else {
        this.searchGet = false;
      }
    },
  },
  mounted() {
    this.$store.commit("loadOn");
    this.getPublicaciones();
  },
  created() {
    this.$store.commit("loadOn");
    this.getPublicaciones();
  },
};
</script>
